public class ConstructorChain {
    static class A {
        A() { System.out.println("A"); }
        A(int x) { this(); System.out.println("A(" + x + ")"); }
    }
    static class B extends A {
        B() { super(5); System.out.println("B"); }
    }
    public static void main(String[] args) {
        new B();
    }
}
